import { Link } from "react-router-dom";
import ActionCell from "./Action";
import { H4 } from "../../../AbstractElements";

export const complaintColumns = (authState) => [
    {
        name: <H4>Sl.No</H4>,
        selector: row => row.Si,
        width: '70px',
        center: true,
    },
    {
        name: <i className="fa fa-gears" style={{ fontSize: '20px' }}></i>,
        selector: row => row.action,
        cell: row => <ActionCell row={row} />,
        center: true,
        width: '90px',
    },
    {
        name: <H4>Subscriber id</H4>,
        id: 'subscriber_id',
        selector: row => row.Sub,
        sortable: true,
        center: true,
        wrap: true,
        minWidth: '120px',
        cell: row => (authState.userRole === 1 || authState.permissions.includes('show-customer-profile')) ?
            <Link style={{ textDecoration: 'underline' }} to={`${process.env.PUBLIC_URL}/customers/customer/userProfile?id=${row.CustomerId}`}>
                {row.Sub}
            </Link> : row.Sub,
    },
    {
        name: <H4>Complaint Id</H4>,
        id: 'complaint_no',
        selector: row => row.ComplaintId || 'N/A',
        sortable: true,
        center: true,
        wrap: true,
        minWidth: '130px',
    },
    {
        name: <H4>Status</H4>,
        selector: row => row.Status,
        minWidth: '105px',
        cell: row => (
            <span
                className={`badge badge-${row.Status}`}
                customer>
                {row.Status.charAt(0).toUpperCase() + row.Status.slice(1)}
            </span>
        ),
    },
    {
        name: <H4>Name</H4>,
        id: 'name',
        selector: row => row.Name,
        sortable: true,
        minWidth: '115px',
        wrap: true
    },
    {
        name: <H4>Area</H4>,
        id: 'area',
        selector: row => row.Area,
        sortable: true,
        minWidth: '115px',
        wrap: true

    },
    {
        name: <H4>Mobile No</H4>,
        id: 'phone',
        selector: row => "+" + row.Mobile,
        sortable: true,
        wrap: true,
        minWidth: '140px'
    },
    {
        name: <H4>Problem type</H4>,
        id: 'problem_type',
        selector: row => row.Problem,
        sortable: true,
        wrap: true,
        minWidth: '140px'

    },
    {
        name: <H4>Updated by</H4>,
        id: 'updated_by',
        selector: row => row.Update,
        sortable: true,
        wrap: true,
        minWidth: '140px'

    },
    {
        name: <H4>Assigned to</H4>,
        id: 'Assig',
        selector: row => row.assign,
        sortable: true,
        wrap: true,
        minWidth: '140px'
    },
    {
        name: <H4>Date</H4>,
        id: 'updated_at',
        selector: row => row.Date,
        sortable: true,
        wrap: true,
        minWidth: '110px'

    },
];